parameters.pythonCode:
clients = _items   # chaque item = une ligne de la data table

slack_client_options = []

for client in clients:
    nom = client["json"].get("nom", "")
    if not nom:
        continue
    slack_client_options.append({
        "text": {
            "type": "plain_text",
            "text": str(nom)
        },
        "value": str(nom)
    })

# Option "Autre" ajoutée à la fin
slack_client_options.append({
    "text": {
        "type": "plain_text",
        "text": "Autre"
    },
    "value": "autre"
})

return [
    {
        "results_ption": slack_client_options
    }
]

